.darma-loader-dual-ring-spinner {
  position: relative;
  display: inline-block;
  width: 58px;
  height: 58px;
  border-radius: 50%;
  color: var(--loader-color, #6366f1);
}
.darma-loader-dual-ring-spinner::before,
.darma-loader-dual-ring-spinner::after {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 4px solid transparent;
  border-top-color: currentColor;
  animation: darma-loader-dual-ring-spinner-spin 1s linear infinite;
}
.darma-loader-dual-ring-spinner::after {
  inset: 10px;
  border-top-color: color-mix(in srgb, var(--loader-color, #6366f1) 35%, transparent);
  animation-direction: reverse;
}
@keyframes darma-loader-dual-ring-spinner-spin { to { transform: rotate(360deg); } }

